DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260308225100_RetireBooks') THEN
    ALTER TABLE "Loans" ALTER COLUMN "Status" SET DEFAULT ('Active');
